   162→  initial: {
   163→    items: [] as Feature[],
   164→    loading: false,
   165→    error: null as string | null,
   166→  },
   167→  reducers: {
   168→    setFeatures: (state, features: Feature[]) => {
   169→      state.items = features;
   170→      state.loading = false;
   171→      state.error = null;
   172→    },
   173→    setLoading: (state, loading: boolean) => {
   174→      state.loading = loading;
   175→    },
   176→    setError: (state, error: string) => {
   177→      state.error = error;
   178→      state.loading = false;
   179→    },
