    26→] as const;
    27→
    28→// Map feature to column based on status and passes flag
    29→function getColumnForFeature(feature: Feature): string {
    30→  // If feature passes, it's DONE regardless of status
    31→  if (feature.passes) {
    32→    return 'done';
    33→  }
    34→
    35→  const status = feature.status.toLowerCase();
    36→
    37→  for (const column of COLUMNS) {
    38→    if (column.statuses.some((s) => status.includes(s))) {
    39→      return column.id;
    40→    }
    41→  }
    42→
    43→  // Default to backlog if status not recognized
    44→  return 'backlog';
    45→}
    46→
    47→// Group features by column
    48→function groupByColumn(features: Feature[]): Record<string, Feature[]> {
    49→  const grouped: Record<string, Feature[]> = {};
    50→
    51→  // Initialize all columns
    52→  for (const column of COLUMNS) {
    53→    grouped[column.id] = [];
    54→  }
    55→
    56→  // Sort features into columns
    57→  for (const feature of features) {
    58→    const columnId = getColumnForFeature(feature);
    59→    grouped[columnId].push(feature);
    60→  }
    61→
    62→  // Sort features within each column by priority
    63→  const priorityOrder: Record<string, number> = {
    64→    critical: 0,
    65→    high: 1,
    66→    medium: 2,
    67→    low: 3,
    68→  };
    69→
    70→  for (const columnId of Object.keys(grouped)) {
    71→    grouped[columnId].sort((a, b) => {
    72→      const aPriority = priorityOrder[a.priority] ?? 4;
    73→      const bPriority = priorityOrder[b.priority] ?? 4;
    74→      return aPriority - bPriority;
    75→    });
    76→  }
    77→
    78→  return grouped;
    79→}
    80→
    81→const columnStyles: React.CSSProperties = {
    82→  minWidth: '220px',
    83→  maxWidth: '280px',
    84→  flex: '1 1 220px',
    85→  height: '100%',
    86→  display: 'flex',
    87→  flexDirection: 'column',
    88→};
    89→
    90→const columnHeaderStyles: React.CSSProperties = {
    91→  backgroundColor: '#f0f0f0',
    92→  borderBottom: '2px solid #06c',
    93→};
    94→
    95→const columnBodyStyles: React.CSSProperties = {
    96→  backgroundColor: '#fafafa',
    97→  flex: 1,
    98→  overflowY: 'auto',
    99→  padding: '8px',
   100→  minHeight: '200px',
   101→};
   102→
   103→export function KanbanBoard({ features }: KanbanBoardProps) {
   104→  const grouped = groupByColumn(features);
   105→
   106→  return (
   107→    <div
   108→      style={{
   109→        width: '100%',
   110→        overflowX: 'auto',
   111→        padding: '8px 0',
   112→      }}
   113→    >
   114→      <Flex
   115→        spaceItems={{ default: 'spaceItemsMd' }}
   116→        alignItems={{ default: 'alignItemsStretch' }}
   117→        style={{ minWidth: 'max-content' }}
   118→      >
   119→        {COLUMNS.map((column) => {
   120→          const columnFeatures = grouped[column.id];
   121→          const count = columnFeatures.length;
   122→
   123→          return (
   124→            <FlexItem key={column.id} style={columnStyles}>
   125→              <Card isFullHeight>
   126→                <CardHeader style={columnHeaderStyles}>
   127→                  <CardTitle>
   128→                    <Flex
   129→                      justifyContent={{ default: 'justifyContentSpaceBetween' }}
