    transition: tweenMedium,
  },
};

// =============================================================================
// Presence Animation Config
// =============================================================================

export const presenceConfig = {
  initial: 'initial',
  animate: 'animate',
  exit: 'exit',
};

export default {
  // Springs
  springSnappy,
  springBouncy,
  springSmooth,
  springGentle,
  // Tweens
  tweenFast,
  tweenMedium,
  tweenSlow,
  // Variants
  fadeVariants,
  fadeUpVariants,
  fadeDownVariants,
  fadeScaleVariants,
  slideRightVariants,
  slideLeftVariants,
  cardVariants,
  modalVariants,
  overlayVariants,
  sidebarVariants,
  rightPanelVariants,
  bottomPanelVariants,
